                if (!s1.equals(s2) && !s1.equals(s3) && !s1.equals(s4)
                        && !s2.equals(s3) && !s2.equals(s4)
                        && !s3.equals(s4)) {
                    return true;
                }
            }
        }
    }
    // If no valid split found, return false
    return false;
}

