static     public boolean canRepresentBST(int[] pre, int n) {
        Stack<Integer> s = new Stack<>();
        int root = Integer.MIN_VALUE;
        for (int i = 0; i < n; i++) {
            // If we encounter a node that is smaller than the allowed minimum (root), it cannot be valid
            if (pre[i] < root) {
                return false;
            }
            // Adjust the allowed minimum (root) for the nodes in the right subtree
            while (!s.empty() && s.peek() < pre[i]) {
                root = s.pop();
            }
            // Push the current node into the stack
            s.push(pre[i]);
        }
        return true;
    }

