static public boolean check(String s1, String s2) {
    int n = s1.length();
    int m = s2.length();
    boolean[][] dp = new boolean[n + 1][m + 1];
    // Initialize all entries to false (Java initializes boolean arrays to false by default,
    // but we include the loops for an explicit translation)
    for (int i = 0; i <= n; i++) {
        for (int j = 0; j <= m; j++) {
            dp[i][j] = false;
        }
    }
    dp[0][0] = true;
    // Process each character of s1
    for (int i = 0; i < s1.length(); i++) {
        for (int j = 0; j <= s2.length(); j++) {
            if (dp[i][j]) {
                // If we can match s1's current character (uppercased) to s2's current character
                if (j < s2.length() && Character.toUpperCase(s1.charAt(i)) == s2.charAt(j)) {
                    dp[i + 1][j + 1] = true;
                }
                // If the current character of s1 is not an uppercase letter, we can drop it
                if (!Character.isUpperCase(s1.charAt(i))) {
                    dp[i + 1][j] = true;
                }
            }
        }
    }
    return dp[n][m];
}

