    public static int isPossible(int n, int index, int modulo, int M, int[] arr, int[][] dp) {
        // Normalize modulo to be within the range [0, M-1]
        modulo = ((modulo % M) + M) % M;
        // Base case: if we've considered all elements, check if modulo is 0
        if (index == n) {
            return (modulo == 0) ? 1 : 0;
        }
        // Return memoized result if available
        if (dp[index][modulo] != -1) {
            return dp[index][modulo];
        }
        // Recursively try adding or subtracting the current element
        int placeAdd = isPossible(n, index + 1, modulo + arr[index], M, arr, dp);
        int placeMinus = isPossible(n, index + 1, modulo - arr[index], M, arr, dp);
        // If either recursive call is successful, mark this state as possible (1), otherwise not possible (0)
        int res = (placeAdd == 1 || placeMinus == 1) ? 1 : 0;
        dp[index][modulo] = res;
        return res;
    }

