    public static String decimalToBinary(double num, int kPrec) {
        StringBuilder binary = new StringBuilder();
        int integral = (int) num;
        double fractional = num - integral;
        // Convert integer part to binary
        while (integral > 0) {
            int rem = integral % 2;
            // Append the digit (as a character) to the string builder
            binary.append((char) (rem + '0'));
            integral /= 2;
        }
        // If no digits were added (number is 0), add '0'
        if (binary.length() == 0) {
            binary.append('0');
        }
        // Reverse the integer part to get correct order
        binary.reverse();
        // Append binary point
        binary.append('.');
        // Convert fractional part to binary
        while (kPrec-- > 0) {
            fractional *= 2;
            int fractBit = (int) fractional;
            if (fractBit == 1) {
                fractional -= fractBit;
                binary.append((char) (1 + '0'));
            } else {
                binary.append((char) (0 + '0'));
            }
        }
        return binary.toString();
    }

