    public static int countPS(char[] str, int n) {
        int[][] dp = new int[n][n];
        boolean[][] P = new boolean[n][n];
        // All substrings of length 1 are palindromes
        for (int i = 0; i < n; i++) {
            P[i][i] = true;
        }
        // Check for substrings of length 2
        for (int i = 0; i < n - 1; i++) {
            if (str[i] == str[i + 1]) {
                P[i][i + 1] = true;
                dp[i][i + 1] = 1;
            }
