static     public int findgroups(int[] arr, int n) {
        int[] c = new int[3]; // array to count remainders 0, 1, 2
        int res = 0;
        // Count the numbers based on modulo 3
        for (int i = 0; i < n; i++) {
            c[arr[i] % 3]++;
        }
        // Count pairs with both numbers having remainder 0
        res += (c[0] * (c[0] - 1)) / 2;
        // Count pairs: one with remainder 1 and one with remainder 2
        res += c[1] * c[2];
        // Count triplets with all numbers having remainder 0
        res += (c[0] * (c[0] - 1) * (c[0] - 2)) / 6;
        // Count triplets with all numbers having remainder 1
        res += (c[1] * (c[1] - 1) * (c[1] - 2)) / 6;
        // Count triplets with all numbers having remainder 2
        res += (c[2] * (c[2] - 1) * (c[2] - 2)) / 6;
        // Count triplets with one number from each remainder group: 0, 1, 2
        res += c[0] * c[1] * c[2];
