    public static String decode(String str) {
        Stack<Integer> integerStack = new Stack<>();
        Stack<Character> stringStack = new Stack<>();
        String temp = "";
        String result = "";
        for (int i = 0; i < str.length(); i++) {
            int count = 0;
            if (str.charAt(i) >= '0' && str.charAt(i) <= '9') {
                // Build the full number (could be multiple digits)
                while (i < str.length() && str.charAt(i) >= '0' && str.charAt(i) <= '9') {
                    count = count * 10 + (str.charAt(i) - '0');
                    i++;
                }
                i--; // adjust for the extra increment
                integerStack.push(count);
            } else if (str.charAt(i) == ']') {
                temp = "";
                count = 0;
                if (!integerStack.isEmpty()) {
                    count = integerStack.pop();
                }
                // Pop characters from the stack until encountering '['
                while (!stringStack.isEmpty() && stringStack.peek() != '[') {
                    temp = stringStack.pop() + temp;
                }
                // Remove the '[' from the stack, if it exists
                if (!stringStack.isEmpty() && stringStack.peek() == '[') {
                    stringStack.pop();
                }
                // Build the repeated substring
                for (int j = 0; j < count; j++) {
                    result = result + temp;
                }
                // Push the expanded substring back onto the character stack
                for (int j = 0; j < result.length(); j++) {
                    stringStack.push(result.charAt(j));
                }
                result = "";
            } else if (str.charAt(i) == '[') {
                if (i - 1 >= 0 && str.charAt(i - 1) >= '0' && str.charAt(i - 1) <= '9') {
                    stringStack.push(str.charAt(i));
                } else {
                    stringStack.push(str.charAt(i));
                    // Push a default repeat count of 1 if no number precedes '['
                    integerStack.push(1);
                }
            } else {
                // For characters that are not digits or brackets, push them onto the stack
                stringStack.push(str.charAt(i));
            }
        }
        // Build the final result from the character stack
        result = "";
        while (!stringStack.isEmpty()) {
            result = stringStack.pop() + result;
        }
        return result;
    }

