        Map<Integer, Integer> value = new HashMap<>();
        int cur = an;
        for (int i = 1; i <= n; i++) {
            // Only store the value if it's not already in the map
            if (!value.containsKey(cur)) {
                value.put(cur, i);
            }
            cur = (int) ((long) cur * an % m);
        }
        // Giant steps: iterate and check for collision
        cur = b;
        for (int i = 0; i <= n; i++) {
            if (value.containsKey(cur)) {
                int ans = value.get(cur) * n - i;
                if (ans < m) {
                    return ans;
                }
            }
            cur = (int) ((long) cur * a % m);
        }
        return -1;
    }

