        int sum = 0;
        for (int i = 0; i < num.length(); i++) {
            // Convert each character to digit and add to sum.
            sum += num.charAt(i) - '0';
        }
        // Check divisibility by 3 (using digit sum) and divisibility by 4 (last two digits form number divisible by 4).
        return sum % 3 == 0 && (d2 * 10 + d1) % 4 == 0;
    } else {
        // For numbers with less than 3 digits, directly parse the string to an integer.
        int number = Integer.parseInt(num);
        return number % 12 == 0;
    }
}

