    public static int lbs(int[] arr) {
        int n = arr.length;
        int[] lis = new int[n];
        // Initialize Longest Increasing Subsequence (LIS) array
        for (int i = 0; i < n; i++) {
            lis[i] = 1;
        }
        // Compute LIS for every index
        for (int i = 1; i < n; i++) {
            for (int j = 0; j < i; j++) {
                if (arr[i] > arr[j] && lis[i] < lis[j] + 1) {
                    lis[i] = lis[j] + 1;
