        int[] lds = new int[n];
        // Initialize Longest Decreasing Subsequence (LDS) array
        for (int i = 0; i < n; i++) {
            lds[i] = 1;
        }
        // Compute LDS for every index
        for (int i = n - 2; i >= 0; i--) {
            for (int j = n - 1; j > i; j--) {
                if (arr[i] > arr[j] && lds[i] < lds[j] + 1) {
                    lds[i] = lds[j] + 1;
                }
            }
        }
        // Find the maximum value of (LIS[i] + LDS[i] - 1)
        int max = lis[0] + lds[0] - 1;
        for (int i = 1; i < n; i++) {
            if (lis[i] + lds[i] - 1 > max) {
