    public static int maxHamming(int[] arr, int n) {
        // Create a new array "brr" with size 2*n + 1
        int[] brr = new int[2 * n + 1];
        // Copy the original array into the first n positions of brr
        for (int i = 0; i < n; i++) {
            brr[i] = arr[i];
        }
        // Copy the original array again into the next n positions of brr
        for (int i = 0; i < n; i++) {
            brr[n + i] = arr[i];
        }
        int maxHam = 0;
        // Loop starting from index 1 up to n-1 to compute different rotations
        for (int i = 1; i < n; i++) {
            int currHam = 0;
            // Compare the rotated array with the original array element by element
            for (int j = i, k = 0; j < (i + n); j++, k++) {
                if (brr[j] != arr[k]) {
                    currHam++;
                }
            }
            // If the entire rotation is different, return n immediately
            if (currHam == n) {
                return n;
            }
            // Update the maximum Hamming distance encountered so far
            maxHam = Math.max(maxHam, currHam);
        }
        return maxHam;
    }

