        Stack<Character> stack = new Stack<>();
        for (char ch : str.toCharArray()) {
            if (ch == ')') {
                char top = stack.peek();
                stack.pop();
                int elementsInside = 0;
                while (top != '(') {
                    elementsInside++;
                    top = stack.peek();
                    stack.pop();
