    public static int binaryMedian(int[][] m, int r, int c) {
        int min = Integer.MAX_VALUE;
        int max = Integer.MIN_VALUE;
        // Find the minimum element from first column and maximum from last column.
        for (int i = 0; i < r; i++) {
            if (m[i][0] < min) {
                min = m[i][0];
            }
            if (m[i][c - 1] > max) {
                max = m[i][c - 1];
            }
        }
        // The desired position of median element when matrix is seen as one sorted array.
        int desired = (r * c + 1) / 2;
        // Binary search between the global minimum and maximum.
        while (min < max) {
            int mid = min + (max - min) / 2;
            int place = 0;
            // Sum counts of elements less than or equal to mid in each row.
            for (int i = 0; i < r; i++) {
                place += upperBound(m[i], mid);
            }
            // If count of numbers <= mid is less than desired, median must be larger.
            if (place < desired)
                min = mid + 1;
            else
                max = mid;
        }
        return min;
    }

