        int ans = 1;
        // Count the number of factors 2
        while (n % 2 == 0) {
            count++;
            n /= 2;
        }
        if (count % 2 != 0) {
            ans *= 2;
        }
        // Check for other prime factors
        for (int i = 3; i <= Math.sqrt(n); i += 2) {
            count = 0;
            while (n % i == 0) {
                count++;
                n /= i;
            }
            if (count % 2 != 0) {
                ans *= i;
            }
        }
