    public static int count(String a, String b) {
        int m = a.length();
        int n = b.length();
        int[][] lookup = new int[m + 1][n + 1];
        // Initialize first row: When a is empty, there are 0 ways (except for empty b, but b's empty column is overwritten next)
        for (int j = 0; j <= n; j++) {
            lookup[0][j] = 0;
        }
        // Initialize first column: An empty b is a subsequence of any prefix of a exactly one time.
        for (int i = 0; i <= m; i++) {
            lookup[i][0] = 1;
        }
        // Fill the lookup table in bottom-up manner.
        for (int i = 1; i <= m; i++) {
            for (int j = 1; j <= n; j++) {
                if (a.charAt(i - 1) == b.charAt(j - 1)) {
                    lookup[i][j] = lookup[i - 1][j - 1] + lookup[i - 1][j];
                } else {
                    lookup[i][j] = lookup[i - 1][j];
                }
            }
        }
        return lookup[m][n];
    }

