static     public boolean isRectangle(List<List<Integer>> matrix) {
        int rows = matrix.size();
        if (rows == 0) return false;
        int columns = matrix.get(0).size();
        // Map each column j to a set of columns k that have been seen with 1 in previous rows.
        Map<Integer, Set<Integer>> table = new HashMap<>();
        // Iterate through each row
        for (int i = 0; i < rows; i++) {
            // For each pair of columns in the current row
            for (int j = 0; j < columns - 1; j++) {
                for (int k = j + 1; k < columns; k++) {
                    // Check if both entries in this row are 1
                    if (matrix.get(i).get(j) == 1 && matrix.get(i).get(k) == 1) {
                        // If previously we've seen a row with both this pair (j and k), then we found a rectangle
                        if (table.containsKey(j) && table.get(j).contains(k)) {
                            return true;
                        }
                        // Otherwise, record that we've seen a pair at (j,k) for this row.
                        table.computeIfAbsent(j, key -> new HashSet<>()).add(k);
                    }
                }
            }
        }
        return false;
    }

