    public static int sumofFactors(int n) {
        if (n % 2 != 0) {
            return 0;
        }
        int res = 1;
        // Loop from 2 to sqrt(n). The int i is promoted to double when compared to Math.sqrt(n)
        for (int i = 2; i <= Math.sqrt(n); i++) {
            int count = 0;
            int curr_sum = 1;
            int curr_term = 1;
            // Divide out all factors of i
            while (n % i == 0) {
                count++;
                n /= i;
                if (i == 2 && count == 1) {
                    curr_sum = 0;
                }
                curr_term *= i;
                curr_sum += curr_term;
            }
            res *= curr_sum;
        }
        // If n is still greater than or equal to 2, it means n is a prime factor.
        if (n >= 2) {
            res *= (1 + n);
        }
        return res;
    }

