    public static int evenSum(int n) {
        int[][] C = new int[n + 1][n + 1];
        for (int i = 0; i <= n; i++) {
            // j goes from 0 to i because i is always less than or equal to n
            for (int j = 0; j <= i; j++) {
                if (j == 0 || j == i) {
                    C[i][j] = 1;
                } else {
                    C[i][j] = C[i - 1][j - 1] + C[i - 1][j];
                }
            }
        }
        int sum = 0;
