    public static boolean isSubSeqDivisible(String str) {
        int n = str.length();
        // dp[i][r] will indicate whether a subsequence ending at position i
        // (or derived from first i digits) can form a number with remainder r mod 8.
        int[][] dp = new int[n + 1][10];
        int[] arr = new int[n + 1];
        // Convert string digits to integer digits, storing them 1-indexed.
        for (int i = 1; i <= n; i++) {
            arr[i] = str.charAt(i - 1) - '0';
        }
        // Build the dp table.
        for (int i = 1; i <= n; i++) {
            // Start a new subsequence with only the current digit.
            dp[i][arr[i] % 8] = 1;
            // Propagate previous subsequences.
            for (int j = 0; j < 8; j++) {
                int newRemainder = (j * 10 + arr[i]) % 8;
                if (dp[i - 1][j] > dp[i][newRemainder]) {
                    dp[i][newRemainder] = dp[i - 1][j];
                }
                if (dp[i - 1][j] > dp[i][j]) {
                    dp[i][j] = dp[i - 1][j];
                }
            }
        }
        // Check if any subsequence ending at some position is divisible by 8.
        for (int i = 1; i <= n; i++) {
            if (dp[i][0] == 1) {
                return true;
            }
        }
        return false;
    }

