    public static int kthLargestSum(int[] arr, int n, int k) {
        // Create prefix sum array of size n+1
        int[] sum = new int[n + 1];
        sum[0] = 0;
        sum[1] = arr[0];
        for (int i = 2; i <= n; i++) {
            sum[i] = sum[i - 1] + arr[i - 1];
        }
        // Use a min-heap to store the k largest sums
        PriorityQueue<Integer> minHeap = new PriorityQueue<>();
        // Generate all subarray sums and maintain the kth largest in the min-heap
        for (int i = 1; i <= n; i++) {
            for (int j = i; j <= n; j++) {
                int x = sum[j] - sum[i - 1];
                if (minHeap.size() < k) {
                    minHeap.add(x);
                } else if (minHeap.peek() < x) {
                    minHeap.poll();
                    minHeap.add(x);
                }
            }
        }
        return minHeap.peek();
    }

