    public static int lenghtOfLongestAP(int[] set, int n) {
        if (n <= 2) return n;
        int[][] L = new int[n][n];
        int llap = 2;
        // Initialize the last column of L with 2
        for (int i = 0; i < n; i++) {
            L[i][n - 1] = 2;
        }
        // Consider every element as the second last element of AP
        for (int j = n - 2; j >= 1; j--) {
            int i = j - 1, k = j + 1;
            // Search for i and k for each j
            while (i >= 0 && k <= n - 1) {
                if (set[i] + set[k] < 2 * set[j]) {
                    k++;
                } else if (set[i] + set[k] > 2 * set[j]) {
                    L[i][j] = 2;
                    i--;
