                    L[i][j] = L[j][k] + 1;
                    llap = Math.max(llap, L[i][j]);
                    i--;
                    k++;
                }
            }
            // If the loop was stopped by k reaching end of array,
            // then set remaining L[i][j] as 2
            while (i >= 0) {
                L[i][j] = 2;
                i--;
            }
        }
