    public static String maximumPalinUsingKChanges(String str, int k) {
        // Convert string to a mutable char array.
        char[] palin = str.toCharArray();
        int l = 0;
        int r = str.length() - 1;
        // First pass: make the string a palindrome by using the maximum of the two digits.
        while (l < r) {
            if (str.charAt(l) != str.charAt(r)) {
                char maxChar = str.charAt(l) > str.charAt(r) ? str.charAt(l) : str.charAt(r);
                palin[l] = maxChar;
                palin[r] = maxChar;
                k--;
            }
            l++;
            r--;
        }
        // If we've exceeded the allowed number of changes, it is not possible.
        if (k < 0)
            return "Not possible";
        // Second pass: maximize the palindrome by trying to set digits to '9'.
        l = 0;
        r = str.length() - 1;
        while (l <= r) {
            if (l == r) {
                // If there's a middle character and at least one change is left, set it to '9'.
                if (k > 0) {
                    palin[l] = '9';
                }
            }
            if (palin[l] < '9') {
                // If both characters are unchanged from the original, we need two changes.
                if (k >= 2 && palin[l] == str.charAt(l) && palin[r] == str.charAt(r)) {
                    k -= 2;
                    palin[l] = '9';
                    palin[r] = '9';
                }
                // If one of the characters was already changed in the first pass, we only need one change.
                else if (k >= 1 && (palin[l] != str.charAt(l) || palin[r] != str.charAt(r))) {
                    k--;
                    palin[l] = '9';
                    palin[r] = '9';
                }
            }
            l++;
            r--;
        }
        return new String(palin);
