    public static int countDivisibleSubseq(String str, int n) {
        int len = str.length();
        int[][] dp = new int[len][n];
        // Initialize the first digit's remainder count.
        dp[0][(str.charAt(0) - '0') % n]++;
        // Process the rest of the string.
        for (int i = 1; i < len; i++) {
            int digit = str.charAt(i) - '0';
            // Starting a new subsequence with the current digit.
            dp[i][digit % n]++;
            // Extend all subsequences ending at previous index.
            for (int j = 0; j < n; j++) {
                // Carry over the count from previous index.
                dp[i][j] += dp[i - 1][j];
                // Append current digit to subsequences ending with remainder j.
                int newMod = (j * 10 + digit) % n;
                dp[i][newMod] += dp[i - 1][j];
            }
        }
        // Return the count of subsequences with remainder zero.
        return dp[len - 1][0];
    }

