    public static double maxAverageOfPath(int[][] cost, int N) {
        // Create dp array of size (N+1) x (N+1)
        int[][] dp = new int[N + 1][N + 1];
        dp[0][0] = cost[0][0];
        // Initialize the first column of dp from the cost matrix
        for (int i = 1; i < N; i++) {
            dp[i][0] = dp[i - 1][0] + cost[i][0];
        }
        // Initialize the first row of dp from the cost matrix
        for (int j = 1; j < N; j++) {
            dp[0][j] = dp[0][j - 1] + cost[0][j];
        }
        // Fill the rest of the dp table
        for (int i = 1; i < N; i++) {
            for (int j = 1; j <= N; j++) {
                dp[i][j] = Math.max(dp[i - 1][j], dp[i][j - 1]) + cost[i][j];
            }
        }
        // Calculate and return the average path cost.
        // Note: denominator is (2 * N - 1)
        return (double) dp[N - 1][N - 1] / (2 * N - 1);
    }

