    public static int knapSack(int[] val, int[] wt, int n, int W) {
        int[][] mat = new int[2][W + 1];
        // By default, new int[][] values are initialized to 0
        int i = 0;
        while (i < n) {
            if (i % 2 != 0) {
                // For odd i, update row 1 using row 0
                for (int j = 1; j <= W; j++) {
                    if (wt[i] <= j && (j - wt[i]) < W) {
                        mat[1][j] = Math.max(val[i] + mat[0][j - wt[i]], mat[0][j]);
                    } else {
                        mat[1][j] = mat[0][j];
                    }
                }
            } else {
                // For even i, update row 0 using row 1
                for (int j = 1; j <= W; j++) {
                    if (wt[i] <= j && (j - wt[i]) < W) {
                        mat[0][j] = Math.max(val[i] + mat[1][j - wt[i]], mat[1][j]);
                    } else {
                        mat[0][j] = mat[1][j];
                    }
                }
            }
            i++;
        }
        return (n % 2 != 0) ? mat[0][W] : mat[1][W];
    }

