    public static int gcd(int a, int b) {
        if (a == 0) return b;
        if (b == 0) return a;
        int k;
        // Factor out powers of 2 from both a and b
        for (k = 0; ((a | b) & 1) == 0; ++k) {
            a >>= 1;
            b >>= 1;
        }
        // Remove remaining factors of 2 in a
        while ((a & 1) == 0) {
            a >>= 1;
        }
        do {
            // Remove factors of 2 in b
            while ((b & 1) == 0) {
                b >>= 1;
            }
            // Make sure a <= b
            if (a > b) {
                int temp = a;
                a = b;
                b = temp;
            }
            b = b - a;
        } while (b != 0);
        // Reintroduce common factors of 2
        return a << k;
    }

