    public static boolean isTriangular(int num) {
        if (num < 0) {
            return false;
        }
        int sum = 0;
        for (int n = 1; sum <= num; n++) {
            sum += n;
            if (sum == num) {
                return true;
            }
        }
        return false;
    }

