    public static int countUnique(int[][] mat, int n, int m) {
        int[] rowSum = new int[n];
        int[] colSum = new int[m];
        // Calculate the sum of each row and column
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < m; j++) {
                if (mat[i][j] != 0) {
                    rowSum[i]++;
                    colSum[j]++;
                }
            }
        }
        int uniqueCount = 0;
        // Count the number of unique elements where the row and column sums are both 1
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < m; j++) {
                if (mat[i][j] != 0 && rowSum[i] == 1 && colSum[j] == 1) {
                    uniqueCount++;
                }
            }
        }
        return uniqueCount;
    }

