    public static int xorZero(String str) {
        int oneCount = 0, zeroCount = 0;
        int n = str.length();
        for (int i = 0; i < n; i++) {
            if (str.charAt(i) == '1') {
                oneCount++;
            } else {
                zeroCount++;
            }
        }
        if (oneCount % 2 == 0) {
            return zeroCount;
        }
        return oneCount;
    }

